CustomField.formula:
AND(
    /* Điều kiện BẮT BUỘC: Case Owner khác user đang xem */
    OwnerId <> $User.Id,

    /* User có nằm trong Follow Up */
    OR(
        CONTAINS(FEC_Follow_Up_User__c, $User.Id),
        CONTAINS(FEC_Follow_Up_User__c, LEFT($User.Id, 15))
    ),

    /* Điều kiện trạng thái / creator */
    OR(
        BEGINS(TEXT(Status), 'Resolved'),
        CreatedById <> $User.Id
    )
)
